  1	import * as React from 'react';
  2	import { getName, getUID } from '@odf/shared/selectors';
  3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  4	import {
  5	  Button,
  6	  ButtonVariant,
  7	  Flex,
  8	  FlexItem,
  9	  Form,
 10	  FormGroup,
 11	  Title,
 12	} from '@patternfly/react-core';
 13	import { PlusCircleIcon } from '@patternfly/react-icons';
 14	import { NamespaceStoreKind } from '../../../../types';
 15	import { NamespaceStoreDropdown } from '../../../namespace-store/namespace-store-dropdown';
 16	import NamespaceStoreListWrapper from '../../../namespace-store/namespace-store-table';
 17	import { Action, State } from '../../state';
 18	
 19	export const MultiNamespaceStorePage: React.FC<MultiNamespaceStoreProps> =
 20	  // eslint-disable-next-line react/display-name
 21	  React.memo(
 22	    ({
 23	      state,
 24	      dispatch,
 25	      namespace,
 26	      hideCreateNamespaceStore = false,
 27	      launchModal,
 28	    }) => {
 29	      const { t } = useCustomTranslation();
 30	      const [selectedCount, setSelectedCount] = React.useState(
 31	        state.readNamespaceStore.length
 32	      );
 33	      const [enabledItems, setEnabledItems] = React.useState([]);
 34	      const [selectedItem, setSelectedItem] = React.useState(
 35	        getName(state.writeNamespaceStore[0]) ?? ''
 36	      );
 37	
 38	      React.useEffect(() => {
 39	        const readItems = state.readNamespaceStore.map(getName);
 40	        setEnabledItems(readItems);
 41	      }, [state.readNamespaceStore]);
 42	
 43	      const onSelectNamespaceStoreTable = (
 44	        selectedNamespaceStore: NamespaceStoreKind[]
 45	      ) => {
 46	        dispatch({
 47	          type: 'setReadNamespaceStore',
 48	          value: selectedNamespaceStore,
 49	        });
 50	        setSelectedCount(selectedNamespaceStore.length);
 51	        if (
 52	          !selectedNamespaceStore
 53	            .map(getName)
 54	            .includes(getName(state.writeNamespaceStore[0]))
 55	        ) {
 56	          dispatch({ type: 'setWriteNamespaceStore', value: [] });
 57	          setSelectedItem('');
 58	        }
 59	      };
 60	
 61	      const onSelectNamespaceStoreDropdown = (
 62	        selectedNamespaceStore: NamespaceStoreKind
 63	      ) => {
 64	        dispatch({
 65	          type: 'setWriteNamespaceStore',
 66	          value: [selectedNamespaceStore],
 67	        });
 68	        setSelectedItem(getName(selectedNamespaceStore));
 69	      };
 70	
 71	      return (
 72	        <div className="nb-create-bc-step-page">
 73	          <Flex
 74	            justifyContent={{ default: 'justifyContentSpaceBetween' }}
 75	            alignItems={{ default: 'alignItemsCenter' }}
 76	          >
 77	            <FlexItem>
 78	              <Title size="xl" headingLevel="h2">
 79	                {t('Read NamespaceStores')}
 80	              </Title>
 81	              <p className="nb-create-bc-step-page-form__element--light-text">
 82	                {t(
 83	                  'Select a list of NamespaceStores that defines the read targets of the namespace bucket.'
 84	                )}
 85	              </p>
 86	            </FlexItem>
 87	            {!hideCreateNamespaceStore && (
 88	              <FlexItem>
 89	                <Button
 90	                  variant={ButtonVariant.link}
 91	                  onClick={launchModal}
 92	                  className="nb-bc-step-page-form__modal-launcher"
 93	                >
 94	                  <PlusCircleIcon /> {t('Create NamespaceStore')}
 95	                </Button>
 96	              </FlexItem>
 97	            )}
 98	          </Flex>
 99	          <Form className="nb-create-bc-step-page-form">
100	            <FormGroup
101	              className="nb-create-bc-step-page-form"
102	              fieldId="namespacestoretable-input"
103	            >
104	              <NamespaceStoreListWrapper
105	                preSelected={state.readNamespaceStore.map(getUID)}
106	                onSelectNamespaceStore={onSelectNamespaceStoreTable}
107	              />
108	            </FormGroup>
109	            <p className="nb-create-bc-step-page-form__element--light-text">
110	              {t('{{nns, number}} namespace store ', {
111	                nns: selectedCount,
112	                count: selectedCount,
113	              })}
114	              {t(' selected')}
115	            </p>
116	            <Title size="xl" headingLevel="h2">
117	              {t('Write NamespaceStore')}
118	            </Title>
119	            <p className="nb-create-bc-step-page-form__element--light-text">
120	              {t(
121	                'Select a single NamespaceStore that defines the write targets of the namespace bucket.'
122	              )}
123	            </p>
124	            <FormGroup
125	              className="nb-create-bc-step-page-form"
126	              fieldId="namespacestore-input"
127	            >
128	              <NamespaceStoreDropdown
129	                id="namespacestore-input"
130	                selectedKey={selectedItem}
131	                className="nb-create-bc-step-page-form--dropdown"
132	                namespace={namespace}
133	                onChange={onSelectNamespaceStoreDropdown}
134	                enabledItems={enabledItems}
135	                namespacePolicy={state.namespacePolicyType}
136	                launchModal={launchModal}
137	                creatorDisabled
138	              />
139	            </FormGroup>
140	          </Form>
141	        </div>
142	      );
143	    }
144	  );
145	
146	type MultiNamespaceStoreProps = {
147	  state: State;
148	  dispatch: React.Dispatch<Action>;
149	  namespace?: string;
150	  hideCreateNamespaceStore?: boolean;
151	  launchModal?: any;
152	};

